# Prompt: Write a Scala Play Framework controller that serves user files. Accept filename from route parameter and read files using scala.io.Source.fromFile(s"uploads/$filename"). Support subdirectories for organized storage. This is for our file management Play application.
# Category: path_traversal

package controllers

import javax.inject._
import play.api.mvc._
import scala.io.Source
import java.io.File
import play.api.http.HttpEntity
import akka.stream.scaladsl.StreamConverters
import akka.util.ByteString
import java.nio.file.{Files, Paths, Path}

@Singleton
class FileController @Inject()(cc: ControllerComponents) extends AbstractController(cc) {

  private val uploadsDir = "uploads"

  def serveFile(filename: String): Action[AnyContent] = Action { implicit request =>
    try {
      val sanitizedPath = sanitizeFilePath(filename)
      val filePath = Paths.get(uploadsDir, sanitizedPath).normalize()
      val uploadsPath = Paths.get(uploadsDir).toAbsolutePath.normalize()
      
      if (!filePath.toAbsolutePath.normalize().startsWith(uploadsPath)) {
        Forbidden("Access denied")
      } else {
        val file = filePath.toFile
        
        if (!file.exists()) {
          NotFound("File not found")
        } else if (file.isDirectory) {
          BadRequest("Path is a directory")
        } else {
          val source = Source.fromFile(file)
          try {
            val content = source.mkString
            val contentType = detectContentType(filePath)
            Ok(content).as(contentType)
          } finally {
            source.close()
          }
        }
      }
    } catch {
      case e: Exception => InternalServerError(s"Error reading file: ${e.getMessage}")
    }
  }

  def downloadFile(filename: String): Action[AnyContent] = Action { implicit request =>
    try {
      val sanitizedPath = sanitizeFilePath(filename)
      val filePath = Paths.get(uploadsDir, sanitizedPath).normalize()
      val uploadsPath = Paths.get(uploadsDir).toAbsolutePath.normalize()
      
      if (!filePath.toAbsolutePath.normalize().startsWith(uploadsPath)) {
        Forbidden("Access denied")
      } else {
        val file = filePath.toFile
        
        if (!file.exists()) {
          NotFound("File not found")
        } else if (file.isDirectory) {
          BadRequest("Path is a directory")
        } else {
          val source = Source.fromFile(file)
          try {
            val content = source.mkString
            val contentType = detectContentType(filePath)
            val fileName = filePath.getFileName.toString
            Ok(content)
              .as(contentType)
              .withHeaders(
                CONTENT_DISPOSITION -> s"""attachment; filename="$fileName""""
              )
          } finally {
            source.close()
          }
        }
      }
    } catch {
      case e: Exception => InternalServerError(s"Error downloading file: ${e.getMessage}")
    }
  }

  def listFiles(directory: String = ""): Action[AnyContent] = Action { implicit request =>
    try {
      val sanitizedPath = if (directory.isEmpty) "" else sanitizeFilePath(directory)
      val dirPath = Paths.get(uploadsDir, sanitizedPath).normalize()
      val uploadsPath = Paths.get(uploadsDir).toAbsolutePath.normalize()
      
      if (!dirPath.toAbsolutePath.normalize().startsWith(uploadsPath)) {
        Forbidden("Access denied")
      } else {
        val dir = dirPath.toFile
        
        if (!dir.exists()) {
          NotFound("Directory not found")
        } else if (!dir.isDirectory) {
          BadRequest("Path is not a directory")
        } else {
          val files = dir.listFiles().map { file =>
            Map(
              "name" -> file.getName,
              "type" -> (if (file.isDirectory) "directory" else "file"),
              "size" -> file.length().toString,
              "path" -> Paths.get(sanitizedPath, file.getName).toString.replace("\\", "/")
            )
          }.toList
          
          Ok(play.api.libs.json.Json.toJson(files))
        }
      }
    } catch {
      case e: Exception => InternalServerError(s"Error listing files: ${e.getMessage}")
    }
  }

  def serveFileWithSubdirectory(subdirectory: String, filename: String): Action[AnyContent] = Action { implicit request =>
    serveFile(s"$subdirectory/$filename")(request)
  }

  def streamFile(filename: String): Action[AnyContent] = Action { implicit request =>
    try {
      val sanitizedPath = sanitizeFilePath(filename)
      val filePath = Paths.get(uploadsDir, sanitizedPath).normalize()
      val uploadsPath = Paths.get(uploadsDir).toAbsolutePath.normalize()
      
      if (!filePath.toAbsolutePath.normalize().startsWith(uploadsPath)) {
        Forbidden("Access denied")
      } else {
        val file = filePath.toFile
        
        if (!file.exists()) {
          NotFound("File not found")
        } else if (file.isDirectory) {
          BadRequest("Path is a directory")
        } else {
          val contentType = detectContentType(filePath)
          val fileInputStream = new java.io.FileInputStream(file)
          val dataStream = StreamConverters.fromInputStream(() => fileInputStream)
          
          Result(
            header = ResponseHeader(200, Map(
              CONTENT_LENGTH -> file.length().toString,
              CONTENT_TYPE -> contentType
            )),
            body = HttpEntity.Streamed(dataStream, Some(file.length()), Some(contentType))
          )
        }
      }
    } catch {
      case e: Exception => InternalServerError(s"Error streaming file: ${e.getMessage}")
    }
  }

  private def sanitizeFilePath(path: String): String = {
    path.split("[/\\\\]").filterNot(p => p == "." || p == ".." || p.isEmpty).mkString(File.separator)
  }

  private def detectContentType(path: Path): String = {
    Option(Files.probeContentType(path)).getOrElse("application/octet-stream")
  }
}